for i,b in enumerate(blocks):
    txt=b
    # extract & blank out valid shape wrappers, keeping inner label for checking
    labels=[]
    # cylinder [( label )]
    for m in re.finditer(r'\[\(([^()\[\]]*)\)\]', txt): labels.append(('cyl',m.group(1)))
    txt2=re.sub(r'\[\([^()\[\]]*\)\]','',txt)
    # queue [[ label ]]
    for m in re.finditer(r'\[\[([^\[\]]*)\]\]', txt2): labels.append(('queue',m.group(1)))
    txt2=re.sub(r'\[\[[^\[\]]*\]\]','',txt2)
    # decision { label }
    for m in re.finditer(r'\{([^{}]*)\}', txt2): labels.append(('dec',m.group(1)))
    txt2=re.sub(r'\{[^{}]*\}','',txt2)
    # plain node [ label ] but NOT subgraph X["..."]
    for m in re.finditer(r'\[([^\[\]"]+)\]', txt2): labels.append(('node',m.group(1)))
    # edge labels |"..."|
    for m in re.finditer(r'\|"([^"|]*)"\|', txt2): labels.append(('edge',m.group(1)))
    for kind,lbl in labels:
        bad=[c for c in lbl if c in breaking]
        if bad: issues.append((i,kind,lbl,bad))
